// modules/repl.ts
import { parse } from "./parser.js";
import { evaluateAsync } from "./eval.js";
import { makeNil } from "./type.js";
import { formatValue } from "./stdlib.js";
import { readLineFromStdin, writeToStdout } from "../platform/stdio.js";
async function readLine() {
    return await readLineFromStdin();
}
function countParens(input) {
    let c = 0, str = false;
    for (let i = 0; i < input.length; i++) {
        const ch = input.charAt(i);
        if (ch === '"' && (i === 0 || input.charAt(i - 1) !== "\\")) {
            str = !str;
        }
        if (!str) {
            if (ch === "(")
                c++;
            else if (ch === ")")
                c--;
        }
    }
    return c;
}
async function readMultiline() {
    let code = "";
    let pc = 0;
    while (true) {
        const prompt = pc > 0 ? "...> " : "HQL> ";
        await writeToStdout(prompt);
        const line = await readLine();
        if (line === null)
            return code.trim() === "" ? null : code;
        code += line + "\n";
        pc = countParens(code);
        if (pc <= 0)
            break;
    }
    return code;
}
export async function repl(env) {
    while (true) {
        const hql = await readMultiline();
        if (hql === null) {
            console.log("\nGoodbye.");
            return;
        }
        if (!hql.trim())
            continue;
        if (hql.trim() === "(exit)") {
            console.log("Goodbye.");
            return;
        }
        try {
            const forms = parse(hql);
            let result = makeNil();
            for (const f of forms) {
                result = await evaluateAsync(f, env);
            }
            console.log(formatValue(result));
        }
        catch (e) {
            console.error("Error:", e.message);
        }
    }
}
